import type { TTSFormat, TTSResult } from "../types";

/**
 * Call Google Cloud Text-to-Speech REST API directly from the browser.
 * The API key must have "Cloud Text-to-Speech API" enabled in Google Cloud Console.
 * Docs: https://cloud.google.com/text-to-speech/docs/reference/rest/v1/text/synthesize
 */
export async function googleTTSSynthesize(
  text: string,
  apiKey: string,
  voiceName = "en-US-Neural2-F",
  languageCode = "en-US",
  format: TTSFormat = "mp3",
  signal?: AbortSignal
): Promise<TTSResult> {
  const audioEncoding = format === "mp3" ? "MP3" : "LINEAR16";
  const url = `https://texttospeech.googleapis.com/v1/text:synthesize?key=${apiKey}`;

  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      input: { text: text.slice(0, 5000) },
      voice: { languageCode, name: voiceName },
      audioConfig: { audioEncoding },
    }),
    signal,
  });

  if (!res.ok) {
    const detail = await res.text().catch(() => res.statusText);
    throw new Error(`Google TTS failed (${res.status}): ${detail}`);
  }

  const data = (await res.json()) as { audioContent: string };
  const binary = atob(data.audioContent);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  const mimeType = format === "mp3" ? "audio/mpeg" : "audio/wav";
  const audioBlob = new Blob([bytes], { type: mimeType });

  // Google TTS does not return phoneme timing; lip-sync uses text-based fallback
  return { audioBlob, alignment: null };
}
