/**
 * Mouth atlas config and viseme timeline helpers for TalkingHead avatar.
 * Edit layout, frame size, and mouthDestRect here or via calibration UI.
 */

export type MouthAtlasLayout = "row" | "grid";

export type MouthAtlasConfig = {
  /** Number of mouth frames in the atlas */
  frameCount: number;
  /** Width of one frame in the atlas image */
  frameWidth: number;
  /** Height of one frame in the atlas image */
  frameHeight: number;
  /** 'row' = single row (default), 'grid' = multi-row (cols inferred from frameCount) */
  layout: MouthAtlasLayout;
  /** Pixels between frames (horizontal and vertical) */
  padding: number;
};

/** Source rectangle in the atlas image for a single mouth frame */
export type SourceRect = {
  sx: number;
  sy: number;
  sw: number;
  sh: number;
};

/** Destination rectangle on the face (parent image) where the mouth is drawn */
export type MouthDestRect = {
  dx: number;
  dy: number;
  dw: number;
  dh: number;
};

/** Default atlas: 1 row, 8 mouth images. For 667×186 use frameWidth 83 (667÷8), frameHeight 186. */
export const DEFAULT_MOUTH_ATLAS: MouthAtlasConfig = {
  frameCount: 8,
  frameWidth: 83,
  frameHeight: 186,
  layout: "row",
  padding: 0,
};

/**
 * Get the source rectangle in the atlas image for mouth frame at index.
 * index is 0..frameCount-1 (viseme 0..7).
 */
export function getMouthSourceRect(config: MouthAtlasConfig, index: number): SourceRect {
  const i = Math.max(0, Math.min(index, config.frameCount - 1));
  const { frameWidth, frameHeight, layout, padding } = config;

  if (layout === "row") {
    // 1 row, 8 frames: frame i at (i * frameWidth, 0) — used for your allinone.png
    const sx = i * (frameWidth + padding);
    return { sx, sy: 0, sw: frameWidth, sh: frameHeight };
  }

  // grid: multi-row (e.g. 4 cols × 2 rows for 8 frames); not used for 1-row atlases
  const cols = 4;
  const row = Math.floor(i / cols);
  const col = i % cols;
  const sx = col * (frameWidth + padding);
  const sy = row * (frameHeight + padding);
  return { sx, sy, sw: frameWidth, sh: frameHeight };
}

/**
 * Default mouth placement on the face (in parent image coordinates as 0–1 fractions).
 * Edit these to align the mouth overlay with the base face, or use the Calibration UI.
 * - dx, dy: position of mouth (left, top) as fraction of face width/height
 * - dw, dh: size of mouth overlay as fraction of face width/height
 */
export const DEFAULT_MOUTH_DEST_RECT: MouthDestRect = {
  dx: 0.35,
  dy: 0.55,
  dw: 0.3,
  dh: 0.2,
};

/** Viseme event: t = seconds from start, v = mouth index 0..N-1 */
export type VisemeEvent = { t: number; v: number };

/** Result of interpolated viseme lookup: blend primary and secondary for coarticulation. */
export type InterpolatedViseme = {
  primaryIndex: number;
  secondaryIndex: number;
  /** 1 = only primary, 0.7 = 70% primary / 30% secondary (coarticulation at boundary) */
  primaryWeight: number;
};

/** Smoothstep for ease-in/ease-out (0 at 0, 1 at 1, smooth S-curve). */
export function smoothstep(x: number): number {
  const t = Math.max(0, Math.min(1, x));
  return t * t * (3 - 2 * t);
}

/** Minimum time (ms) to hold each viseme before allowing transition (reduces flicker). */
export const VISEME_HOLD_MS = 60;
/** Crossfade duration (ms) between consecutive visemes for smooth blending. */
export const CROSSFADE_MS = 80;

/**
 * Binary search: largest index i such that visemeEvents[i].t <= t.
 * Returns 0 if no events.
 */
function findVisemeIndexAtTime(visemeEvents: VisemeEvent[], t: number): number {
  if (!visemeEvents.length) return 0;
  let lo = 0;
  let hi = visemeEvents.length - 1;
  if (visemeEvents[0]!.t > t) return 0;
  if (visemeEvents[hi]!.t <= t) return hi;
  while (lo + 1 < hi) {
    const mid = (lo + hi) >> 1;
    if (visemeEvents[mid]!.t <= t) lo = mid;
    else hi = mid;
  }
  return lo;
}

/**
 * Get current viseme index from timeline at time t (seconds).
 * Applies minimum hold (VISEME_HOLD_MS): don't switch to next viseme until hold has elapsed.
 * If no events, returns 0 (closed mouth).
 */
export function getVisemeAtTime(visemeEvents: VisemeEvent[], t: number): number {
  if (!visemeEvents.length) return 0;
  const holdS = VISEME_HOLD_MS / 1000;
  const idx = findVisemeIndexAtTime(visemeEvents, t);
  const segStart = visemeEvents[idx]!.t;
  if (idx + 1 < visemeEvents.length) {
    const nextT = visemeEvents[idx + 1]!.t;
    if (nextT - segStart < holdS && t < segStart + holdS) return visemeEvents[idx]!.v;
  }
  return visemeEvents[idx]!.v;
}

export type InterpolatedVisemeOptions = {
  /** Coarticulation window in ms; blend toward next viseme in the last N ms of each segment. */
  blendWindowMs?: number;
  /** At segment boundary: primaryWeight = coarticulationPrimary (e.g. 0.7 = 70% current, 30% next). */
  coarticulationPrimary?: number;
};

const DEFAULT_BLEND_WINDOW_MS = CROSSFADE_MS; // 80ms crossfade between visemes
const DEFAULT_COARTICULATION_PRIMARY = 0.7; // 70/30 blend at boundary

/**
 * Get interpolated viseme state at time t for smooth, flicker-free rendering.
 * - Enforces hold + coarticulation: in the last blendWindowMs of a segment, eases toward next viseme (ease-in/ease-out).
 * - Returns primary + secondary indices and primaryWeight for client-side blending (60fps).
 */
export function getInterpolatedVisemeAtTime(
  visemeEvents: VisemeEvent[],
  t: number,
  options: InterpolatedVisemeOptions = {}
): InterpolatedViseme {
  const blendWindowMs = options.blendWindowMs ?? DEFAULT_BLEND_WINDOW_MS;
  const coarticulationPrimary = options.coarticulationPrimary ?? DEFAULT_COARTICULATION_PRIMARY;
  const blendWindowS = blendWindowMs / 1000;

  if (!visemeEvents.length) {
    return { primaryIndex: 0, secondaryIndex: 0, primaryWeight: 1 };
  }

  const i = findVisemeIndexAtTime(visemeEvents, t);

  const current = visemeEvents[i]!.v;
  const t0 = visemeEvents[i]!.t;
  const t1 = i + 1 < visemeEvents.length ? visemeEvents[i + 1]!.t : t0 + 1;
  const segmentDur = t1 - t0;
  const next = i + 1 < visemeEvents.length ? visemeEvents[i + 1]!.v : current;

  if (next === current || segmentDur <= 0) {
    return { primaryIndex: current, secondaryIndex: current, primaryWeight: 1 };
  }

  const windowLen = Math.min(blendWindowS, segmentDur * 0.4);
  const blendStart = t1 - windowLen;
  if (t < blendStart) {
    return { primaryIndex: current, secondaryIndex: next, primaryWeight: 1 };
  }

  const raw = (t - blendStart) / windowLen;
  const eased = smoothstep(raw);
  const primaryWeight = 1 - (1 - coarticulationPrimary) * eased;
  return { primaryIndex: current, secondaryIndex: next, primaryWeight };
}

