// ---------------------------------------------------------------------------
// Per-character viseme map (loaded from viseme_map.json produced by pipeline)
// ---------------------------------------------------------------------------

/** Raw structure of viseme_map.json written by the pipeline. */
export type VisemeMap = {
  /** Maps viseme name (e.g. "MBP", "FV") to list of atlas frameIndices for that viseme. */
  visemeFrames: Record<string, number[]>;
  /** Atlas frameIndices whose phoneme could not be resolved to a known viseme. */
  unknownFrames: number[];
};

/**
 * Pick a single representative frameIndex for a viseme.
 * Uses the middle frame to avoid edge/transition frames.
 */
export function pickVisemeFrame(frames: number[]): number {
  if (!frames || frames.length === 0) return 0;
  return frames[Math.floor(frames.length / 2)]!;
}

/**
 * Runtime phoneme remapping applied before any viseme_map.json lookup.
 * Keys are ARPAbet phonemes to redirect; values are the phoneme to use instead.
 * Both the individual-key and group-key lookups use the remapped phoneme.
 *
 * e.g. "IH" → "AY" means the short-i sound (as in "bit") uses the AY mouth shape.
 * Adjust here to fine-tune how any phoneme looks on a given character set.
 */
const PHONEME_REMAP: Record<string, string> = {
  IH: "AY",
};

/**
 * ARPAbet phoneme → viseme group name.
 * Individual keys (e.g. "L") are tried first; the group key (e.g. "TDNL") is
 * the fallback when no individual entry exists in the character's viseme_map.json.
 */
const PHONEME_TO_VISEME: Record<string, string> = {
  SIL: "REST", SP: "REST", SPN: "REST",
  M: "MBP", B: "MBP", P: "MBP",
  F: "FV", V: "FV",
  TH: "TH", DH: "TH",
  S: "SZ", Z: "SZ",
  SH: "SHCHJ", CH: "SHCHJ", JH: "SHCHJ", ZH: "SHCHJ",
  T: "TDNL", D: "TDNL", N: "TDNL", L: "TDNL",
  K: "KGNG", G: "KGNG", NG: "KGNG",
  HH: "AA",                          // aspirated H — open mouth, similar to AA/AH
  R: "R", ER: "R",
  W: "W",
  Y: "Y",
  AA: "AA", AH: "AA",
  AE: "AE",
  EH: "EH",
  IH: "IH",
  IY: "EE",
  UH: "UH",
  UW: "OO",
  OW: "OH", AO: "OH",
  AY: "AY",
  AW: "AW",
  OY: "OY",
  EY: "EY",
  YUW: "YUW",
};

/**
 * Build a phoneme → full frame-index array lookup from viseme_map.json.
 * Returns every frame the pipeline assigned to each phoneme (individual key
 * preferred over group key, same precedence as buildPhonemeFrameIndex).
 * Used by buildVisemeTimelineFromAlignmentAndMap to spread frames across the
 * phoneme's real time window instead of freezing on a single representative.
 */
export function buildPhonemeFrameArrays(visemeMap: VisemeMap): Record<string, number[]> {
  const restFrames = visemeMap.visemeFrames["REST"];
  const restFallback = restFrames ?? [0];
  const result: Record<string, number[]> = {};
  for (const [phoneme, visemeName] of Object.entries(PHONEME_TO_VISEME)) {
    const effectivePhoneme = PHONEME_REMAP[phoneme] ?? phoneme;
    const effectiveViseme = PHONEME_REMAP[visemeName] ?? visemeName;
    const frames =
      visemeMap.visemeFrames[effectivePhoneme] ??
      visemeMap.visemeFrames[effectiveViseme] ??
      restFallback;
    result[phoneme] = frames;
  }
  return result;
}

/**
 * Build a phoneme-to-frameIndex lookup from viseme_map.json.
 *
 * Maps every known ARPAbet phoneme to the atlas frameIndex the pipeline
 * assigned to that viseme, so timeline functions produce frameIndices that
 * are valid for THIS character's sprite sheet.
 *
 * Phonemes that share a viseme get the same representative frameIndex.
 * Falls back to 0 for any phoneme not covered by the map.
 */
export function buildPhonemeFrameIndex(visemeMap: VisemeMap): Record<string, number> {
  const result: Record<string, number> = {};
  const restFrames = visemeMap.visemeFrames["REST"];
  const restIdx = restFrames ? pickVisemeFrame(restFrames) : 0;
  const arrays = buildPhonemeFrameArrays(visemeMap);

  const missingKeys: string[] = [];
  for (const [phoneme, visemeName] of Object.entries(PHONEME_TO_VISEME)) {
    const effectivePhoneme = PHONEME_REMAP[phoneme] ?? phoneme;
    const effectiveViseme = PHONEME_REMAP[visemeName] ?? visemeName;
    const hasIndividual = !!visemeMap.visemeFrames[effectivePhoneme];
    const hasGroup = !!visemeMap.visemeFrames[effectiveViseme];
    if (!hasIndividual && !hasGroup) {
      const remapNote = effectivePhoneme !== phoneme ? ` remapped→"${effectivePhoneme}"` : "";
      missingKeys.push(`${phoneme}${remapNote} (tried keys: "${effectivePhoneme}", "${effectiveViseme}")`);
    }
    const frames = arrays[phoneme] ?? [restIdx];
    result[phoneme] = pickVisemeFrame(frames);
    result[`${phoneme}0`] = result[phoneme]!;
    result[`${phoneme}1`] = result[phoneme]!;
  }
  if (missingKeys.length > 0) {
    console.warn(
      `[TalkyHeads] buildPhonemeFrameIndex: ${missingKeys.length} phoneme(s) not found in viseme_map.json — falling back to REST frame.\n` +
      missingKeys.map(k => `  • ${k}`).join("\n")
    );
  }
  return result;
}

